import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import './app.css';
import AICoach from './components/AICoach';
import Therapy from './components/Therapy';
import Community from './components/Community';
import Report from './components/Report';
import Profile from './components/Profile';
import Chat from './components/Chat';


const MoodMate = () => {
  const [activeTab, setActiveTab] = useState('chat');
  const [user] = useState({
    username: 'Arnav._.singh__',
    is_premium: true,
    streak: 6,
    lastMood: 'low',
    lastSession: 'kal raat'
  });
  
  const [showNotification, setShowNotification] = useState(true);
  const [notificationMsg, setNotificationMsg] = useState('');

  React.useEffect(() => {
    const messages = [
      `${user.username}… ${user.lastSession} tum thoda ${user.lastMood} feel kar rahe the… aaj check karna chahoge? 🫂`,
      `Welcome back ${user.username}… Day ${user.streak} streak 🔥 Aaj ka mission ready hai.`,
      `Your ${user.streak}-day streak is at risk. Don't let it break ⚠️`,
      `A rare mystery drop is waiting for you today 🎁`
    ];
    setNotificationMsg(messages[Math.floor(Math.random() * messages.length)]);
    const timer = setTimeout(() => setShowNotification(false), 8000); // 8 second visibility
    return () => clearTimeout(timer);
  }, []);

  return (
    <div className="app-container">
      {/* Smart Psych Push Layer */}
      <AnimatePresence>
        {showNotification && (
          <motion.div 
            initial={{ y: -50, opacity: 0 }} 
            animate={{ y: 0, opacity: 1 }} 
            exit={{ y: -50, opacity: 0 }}
            style={{ background: 'linear-gradient(90deg, #f43f5e, #8b5cf6)', color: 'white', padding: '14px 20px', textAlign: 'center', fontWeight: 'bold', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '15px', boxShadow: '0 4px 15px rgba(244, 63, 94, 0.3)' }}
          >
            <span>{notificationMsg}</span>
            <button onClick={() => setShowNotification(false)} style={{ background: 'rgba(255,255,255,0.2)', border: 'none', color: 'white', borderRadius: '50%', width: '24px', height: '24px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>✕</button>
          </motion.div>
        )}
      </AnimatePresence>
      
      {/* Header */}
      <header className="app-header">
        <div className="header-left">
          <h1>MoodMate</h1>
          <div className="nav-tabs">
            <button 
              className={activeTab === 'chat' ? 'nav-tab active' : 'nav-tab'}
              onClick={() => setActiveTab('chat')}
            >
              💬 Chat
            </button>
            <button 
              className={activeTab === 'ai-coach' ? 'nav-tab active' : 'nav-tab'}
              onClick={() => setActiveTab('ai-coach')}
            >
              🤖 AI Coach
            </button>
            <button 
              className={activeTab === 'therapy' ? 'nav-tab active' : 'nav-tab'}
              onClick={() => setActiveTab('therapy')}
            >
              👨‍⚕️ Therapy
            </button>
            <button 
              className={activeTab === 'community' ? 'nav-tab active' : 'nav-tab'}
              onClick={() => setActiveTab('community')}
            >
              🌍 Community
            </button>
            <button 
              className={activeTab === 'report' ? 'nav-tab active' : 'nav-tab'}
              onClick={() => setActiveTab('report')}
            >
              📊 Report
            </button>
            <button 
              className={activeTab === 'profile' ? 'nav-tab active' : 'nav-tab'}
              onClick={() => setActiveTab('profile')}
            >
              👤 Profile
            </button>
          </div>
        </div>
        <div className="header-right" style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
          <div style={{ position: 'relative', cursor: 'pointer' }} title="Notifications">
             <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#64748b" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"></path>
                <path d="M13.73 21a2 2 0 0 1-3.46 0"></path>
             </svg>
             {/* Red dot for psychology hook */}
             <div style={{ position: 'absolute', top: 0, right: 0, width: '10px', height: '10px', background: '#ef4444', borderRadius: '50%', border: '2px solid white' }}></div>
          </div>
          <div 
            onClick={() => setActiveTab('profile')}
            style={{ width: '42px', height: '42px', borderRadius: '50%', background: 'linear-gradient(135deg, #FF007F, #7000FF)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 'bold', fontSize: '18px', cursor: 'pointer', boxShadow: '0 4px 15px rgba(112,0,255,0.3)', transition: 'transform 0.2s' }} 
            onMouseOver={e => e.currentTarget.style.transform='scale(1.05)'} 
            onMouseOut={e => e.currentTarget.style.transform='scale(1)'}
            title="Profile & Settings"
          >
            {user.username.charAt(0).toUpperCase()}
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="app-main">
        <AnimatePresence mode="wait">
          <motion.div
            key={activeTab}
            initial={{ opacity: 0, y: 15 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.98 }}
            transition={{ duration: 0.3, ease: 'easeOut' }}
            style={{ width: '100%', height: '100%' }}
          >
            {activeTab === 'chat' && <Chat user={user} />}
            {activeTab === 'ai-coach' && <AICoach user={user} />}
            {activeTab === 'therapy' && <Therapy user={user} />}
            {activeTab === 'community' && <Community user={user} />}
            {activeTab === 'report' && <Report user={user} />}
            {activeTab === 'profile' && <Profile user={user} />}
          </motion.div>
        </AnimatePresence>
      </main>
    </div>
  );
};

export default MoodMate;
